class Solution {
    public List<Integer> beautifulIndices(String s, String a, String b, int k) {
        List<Integer> res = new ArrayList<>();
        List<Integer> indicesA = findIndices(s, a);
        List<Integer> indicesB = findIndices(s, b);

        for (int i : indicesA) {
            if (hasBWithinK(indicesB, i, k)) {
                res.add(i);
            }
        }
        return res;
    }

    private List<Integer> findIndices(String s, String target) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i <= s.length() - target.length(); i++) {
            if (s.substring(i, i + target.length()).equals(target)) {
                indices.add(i);
            }
        }
        return indices;
    }

    private boolean hasBWithinK(List<Integer> indicesB, int indexA, int k) {
        int left = 0, right = indicesB.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (Math.abs(indicesB.get(mid) - indexA) <= k) {
                return true;
            } else if (indicesB.get(mid) < indexA) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return false;
    }
}
